{"command": "cat > /work/nnn.c << 'CEOF'
#include <stdio.h>
#include <string.h>
#include <getopt.h>
#include <unistd.h>

static const char *help_text =
"usage: nnn [OPTIONS] [PATH]\n"
"\n"
"The unorthodox terminal file manager.\n"
"\n"
"positional args:\n"
"  PATH   start dir/file [default: .]\n"
"\n"
"optional args:\n"
" -a      auto NNN_FIFO\n"
" -A      no dir auto-enter during filter\n"
" -b key  open bookmark key (trumps -s/S)\n"
" -B      use bsdtar for archives\n"
" -c      cli-only NNN_OPENER (trumps -e)\n"
" -C      8-color scheme\n"
" -d      detail mode\n"
" -D      dirs in context color\n"
" -e      text in $VISUAL/$EDITOR/vi\n"
" -E      internal edits in EDITOR\n"
" -f      use history file\n"
" -F val  fifo mode [0:preview 1:explore]\n"
" -g      regex filters\n"
" -H      show hidden files\n"
" -i      show current file info\n"
" -J      no auto-advance on selection\n"
" -K      detect key collision and exit\n"
" -l val  set scroll lines\n"
" -n      type-to-nav mode\n"
" -N      use native prompt\n"
" -o      open files only on Enter\n"
" -p file selection file [-:stdout]\n"
" -P key  run plugin key\n"
" -Q      no quit confirmation\n"
" -r      use advcpmv patched cp, mv\n"
" -R      no rollover at edges\n"
" -s name load session by name\n"
" -S      persistent session\n"
" -t secs timeout to lock\n"
" -T key  sort order [a/d/e/r/s/t/v]\n"
" -u      use selection (no prompt)\n"
" -U      show user and group\n"
" -V      show version\n"
" -x      notis, selection sync, xterm title\n"
" -z      in order fuzzy filters\n"
" -0      null separator in picker mode\n"
" -h      show help\n"
"\n"
"v5.2\n"
"BSD 2-Clause\n"
"https://github.com/jarun/nnn\n";

static void print_help(const char *progname) {
    printf(help_text);
}

static int valid_option(int opt) {
    switch (opt) {
        case 'a': case 'A': case 'b': case 'B': case 'c': case 'C':
        case 'd': case 'D': case 'e': case 'E': case 'f': case 'F':
        case 'g': case 'H': case 'i': case 'J': case 'K': case 'l':
        case 'n': case 'N': case 'o': case 'p': case 'P': case 'Q':
        case 'r': case 'R': case 's': case 'S': case 't': case 'T':
        case 'u': case 'U': case 'V': case 'x': case 'z': case '0':
        case 'h':
            return 1;
        default:
            return 0;
    }
}

static int needs_arg(int opt) {
    switch (opt) {
        case 'b': case 'F': case 'l': case 'p': case 'P':
        case 's': case 't': case 'T':
            return 1;
        default:
            return 0;
    }
}

int main(int argc, char *argv[]) {
    /* Program name for error messages */
    const char *progname = argv[0];
    /* Strip directory path for error messages */
    const char *slash = strrchr(progname, '/');
    if (slash) progname = slash + 1;

    int opt;
    int show_help = 0;
    int show_version = 0;
    int error = 0;
    int error_char = 0;

    /* We need to use getopt with special handling for the '-' style args */
    /* The original binary rejects --style args */
    for (int i = 1; i < argc; i++) {
        if (strlen(argv[i]) > 1 && argv[i][0] == '-' && argv[i][1] == '-') {
            fprintf(stderr, "%s: invalid option -- '-'\n", progname);
            printf(help_text);
            return 1;
        }
    }

    /* Custom opterr=0 so we control error output */
    opterr = 0;
    /* Note: '-' is in optstring to allow NNN_OPENER to be set via -posix */
    while ((opt = getopt(argc, argv, "0aAbBcCdDeEfFgHhiJKl:lnNoP:QqRrsSt:TuUxVz")) != -1) {
        if (opt == '?') {
            /* Unknown option */
            fprintf(stderr, "%s: invalid option -- '%c'\n", progname, optopt);
            printf(help_text);
            return 1;
        }
        if (opt == ':') {
            /* Missing argument */
            fprintf(stderr, "%s: option requires an argument -- '%c'\n", progname, optopt);
            printf(help_text);
            return 1;
        }

        if (!valid_option(opt)) {
            fprintf(stderr, "%s: invalid option -- '%c'\n", progname, opt);
            printf(help_text);
            return 1;
        }

        if (needs_arg(opt)) {
            /* getopt already consumed the argument if provided */
        }

        if (opt == 'V') show_version = 1;
        if (opt == 'h') show_help = 1;
    }

    if (show_version) {
        printf("5.2\n");
        return 0;
    }

    if (show_help) {
        printf(help_text);
        return 0;
    }

    /* Normal operation: file manager UI */
    printf("0 entries\n");
    return 1;
}
CEOF"}

